package edu.comillas.icai.gitt.pat.spring.jpa3.controller;

import edu.comillas.icai.gitt.pat.spring.jpa3.entity.Reserva;
import edu.comillas.icai.gitt.pat.spring.jpa3.entity.Usuario;
import edu.comillas.icai.gitt.pat.spring.jpa3.service.DisponibilidadService;
import edu.comillas.icai.gitt.pat.spring.jpa3.service.PistaService;
import edu.comillas.icai.gitt.pat.spring.jpa3.service.ReservaService;
import edu.comillas.icai.gitt.pat.spring.jpa3.service.UsuarioService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.server.ResponseStatusException;

import java.time.LocalDate;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
@CrossOrigin(origins = "*")
@RestController
@RequestMapping("/pistaPadel")
public class ReservaController {

    @Autowired
    private ReservaService reservaService;

    @Autowired
    private DisponibilidadService disponibilidadService;

    @Autowired
    private UsuarioService usuarioService;

    @Autowired
    private PistaService pistaService;

    private Usuario obtenerUsuarioActual() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        String email = auth.getName();

        return usuarioService.buscarPorEmail(email)
                .orElseThrow(() -> new ResponseStatusException(
                        HttpStatus.UNAUTHORIZED,
                        "Usuario autenticado no encontrado"
                ));
    }

    @PostMapping("/reservations")
    public Reserva crear(@RequestBody Reserva reserva) {
        Usuario usuario = obtenerUsuarioActual();
        reserva.usuario = usuario;
        return reservaService.crearReserva(reserva);
    }

    @GetMapping("/reservations")
    public List<Reserva> listar() {
        Usuario usuario = obtenerUsuarioActual();

        if (esAdmin(usuario)) {
            return reservaService.listarTodas();
        }

        return reservaService.obtenerReservasPorUsuario(usuario.id);
    }

    @GetMapping("/reservations/{id}")
    public Reserva obtenerPorId(@PathVariable Long id) {
        Usuario usuario = obtenerUsuarioActual();
        Reserva reserva = reservaService.obtenerPorId(id);

        if (!esAdmin(usuario) && !reserva.usuario.id.equals(usuario.id)) {
            throw new ResponseStatusException(
                    HttpStatus.FORBIDDEN,
                    "No autorizado"
            );
        }

        return reserva;
    }

    @PatchMapping("/reservations/{id}")
    public Reserva modificar(@PathVariable Long id, @RequestBody Reserva datos) {
        Usuario usuario = obtenerUsuarioActual();
        Reserva reserva = reservaService.obtenerPorId(id);

        if (!esAdmin(usuario) && !reserva.usuario.id.equals(usuario.id)) {
            throw new ResponseStatusException(
                    HttpStatus.FORBIDDEN,
                    "No autorizado"
            );
        }

        if (datos.fechaReserva != null) {
            reserva.fechaReserva = datos.fechaReserva;
        }
        if (datos.horaInicio != null) {
            reserva.horaInicio = datos.horaInicio;
        }
        if (datos.duracionMinutos != null) {
            reserva.duracionMinutos = datos.duracionMinutos;
        }

        return reservaService.modificarReserva(reserva);
    }

    @DeleteMapping("/reservations/{id}")
    public void cancelar(@PathVariable Long id) {
        Usuario usuario = obtenerUsuarioActual();
        Reserva reserva = reservaService.obtenerPorId(id);

        if (!esAdmin(usuario) && !reserva.usuario.id.equals(usuario.id)) {
            throw new ResponseStatusException(
                    HttpStatus.FORBIDDEN,
                    "No autorizado"
            );
        }

        reservaService.cancelarReserva(id);
    }

    @GetMapping("/courts/{id}/availability")
    public List<String> disponibilidad(@PathVariable Long id,
                                       @RequestParam LocalDate date) {
        pistaService.buscarPista(id);
        return disponibilidadService.calcularDisponibilidad(id, date);
    }

    @GetMapping("/admin/reservations")
    public List<Reserva> listarAdmin(@RequestParam(required = false) LocalDate date,
                                     @RequestParam(required = false) Long courtId,
                                     @RequestParam(required = false) Long userId) {
        Usuario usuario = obtenerUsuarioActual();

        if (!esAdmin(usuario)) {
            throw new ResponseStatusException(
                    HttpStatus.FORBIDDEN,
                    "Solo ADMIN"
            );
        }

        List<Reserva> reservas = reservaService.listarTodas();

        if (date != null) {
            reservas.removeIf(r -> !date.equals(r.fechaReserva));
        }
        if (courtId != null) {
            reservas.removeIf(r -> !courtId.equals(r.pista.idPista));
        }
        if (userId != null) {
            reservas.removeIf(r -> !userId.equals(r.usuario.id));
        }

        return reservas;
    }

    @GetMapping("/availability")
    public Map<Long, List<String>> disponibilidadGlobal(@RequestParam LocalDate date) {
        Map<Long, List<String>> resultado = new HashMap<>();

        pistaService.listarPistas().forEach(pista ->
                resultado.put(
                        pista.idPista,
                        disponibilidadService.calcularDisponibilidad(pista.idPista, date)
                )
        );

        return resultado;
    }

    private boolean esAdmin(Usuario usuario) {
        return usuario.rol != null && "ADMIN".equalsIgnoreCase(usuario.rol.nombreRol);
    }
}

package edu.comillas.icai.gitt.pat.spring.jpa3.controller;

import edu.comillas.icai.gitt.pat.spring.jpa3.entity.Reserva;
import edu.comillas.icai.gitt.pat.spring.jpa3.entity.Usuario;
import edu.comillas.icai.gitt.pat.spring.jpa3.service.DisponibilidadService;
import edu.comillas.icai.gitt.pat.spring.jpa3.service.PistaService;
import edu.comillas.icai.gitt.pat.spring.jpa3.service.ReservaService;
import edu.comillas.icai.gitt.pat.spring.jpa3.service.UsuarioService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.server.ResponseStatusException;

import java.time.LocalDate;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
@CrossOrigin(origins = "*")
@RestController
@RequestMapping("/pistaPadel")
public class ReservaController {

    @Autowired
    private ReservaService reservaService;

    @Autowired
    private DisponibilidadService disponibilidadService;

    @Autowired
    private UsuarioService usuarioService;

    @Autowired
    private PistaService pistaService;

    private Usuario obtenerUsuarioActual() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        String email = auth.getName();

        return usuarioService.buscarPorEmail(email)
                .orElseThrow(() -> new ResponseStatusException(
                        HttpStatus.UNAUTHORIZED,
                        "Usuario autenticado no encontrado"
                ));
    }

    @PostMapping("/reservations")
    public Reserva crear(@RequestBody Reserva reserva) {
        Usuario usuario = obtenerUsuarioActual();
        reserva.usuario = usuario;
        return reservaService.crearReserva(reserva);
    }

    @GetMapping("/reservations")
    public List<Reserva> listar() {
        Usuario usuario = obtenerUsuarioActual();

        if (esAdmin(usuario)) {
            return reservaService.listarTodas();
        }

        return reservaService.obtenerReservasPorUsuario(usuario.id);
    }

    @GetMapping("/reservations/{id}")
    public Reserva obtenerPorId(@PathVariable Long id) {
        Usuario usuario = obtenerUsuarioActual();
        Reserva reserva = reservaService.obtenerPorId(id);

        if (!esAdmin(usuario) && !reserva.usuario.id.equals(usuario.id)) {
            throw new ResponseStatusException(
                    HttpStatus.FORBIDDEN,
                    "No autorizado"
            );
        }

        return reserva;
    }

    @PatchMapping("/reservations/{id}")
    public Reserva modificar(@PathVariable Long id, @RequestBody Reserva datos) {
        Usuario usuario = obtenerUsuarioActual();
        Reserva reserva = reservaService.obtenerPorId(id);

        if (!esAdmin(usuario) && !reserva.usuario.id.equals(usuario.id)) {
            throw new ResponseStatusException(
                    HttpStatus.FORBIDDEN,
                    "No autorizado"
            );
        }

        if (datos.fechaReserva != null) {
            reserva.fechaReserva = datos.fechaReserva;
        }
        if (datos.horaInicio != null) {
            reserva.horaInicio = datos.horaInicio;
        }
        if (datos.duracionMinutos != null) {
            reserva.duracionMinutos = datos.duracionMinutos;
        }

        return reservaService.modificarReserva(reserva);
    }

    @DeleteMapping("/reservations/{id}")
    public void cancelar(@PathVariable Long id) {
        Usuario usuario = obtenerUsuarioActual();
        Reserva reserva = reservaService.obtenerPorId(id);

        if (!esAdmin(usuario) && !reserva.usuario.id.equals(usuario.id)) {
            throw new ResponseStatusException(
                    HttpStatus.FORBIDDEN,
                    "No autorizado"
            );
        }

        reservaService.cancelarReserva(id);
    }

    @GetMapping("/courts/{id}/availability")
    public List<String> disponibilidad(@PathVariable Long id,
                                       @RequestParam LocalDate date) {
        pistaService.buscarPista(id);
        return disponibilidadService.calcularDisponibilidad(id, date);
    }

    @GetMapping("/reservations/availability")
    public List<String> disponibilidadLegacy(@RequestParam(required = false) LocalDate date,
                                             @RequestParam(required = false) LocalDate fecha,
                                             @RequestParam(required = false) Long idPista,
                                             @RequestParam(required = false) Long courtId) {
        LocalDate fechaConsulta = date != null ? date : fecha;
        Long pistaId = idPista != null ? idPista : courtId;

        if (fechaConsulta == null || pistaId == null) {
            throw new ResponseStatusException(
                    HttpStatus.BAD_REQUEST,
                    "Se requiere fecha y pista"
            );
        }

        pistaService.buscarPista(pistaId);
        return disponibilidadService.calcularDisponibilidad(pistaId, fechaConsulta);
    }

    @GetMapping("/admin/reservations")
    public List<Reserva> listarAdmin(@RequestParam(required = false) LocalDate date,
                                     @RequestParam(required = false) Long courtId,
                                     @RequestParam(required = false) Long userId) {
        Usuario usuario = obtenerUsuarioActual();

        if (!esAdmin(usuario)) {
            throw new ResponseStatusException(
                    HttpStatus.FORBIDDEN,
                    "Solo ADMIN"
            );
        }

        List<Reserva> reservas = reservaService.listarTodas();

        if (date != null) {
            reservas.removeIf(r -> !date.equals(r.fechaReserva));
        }
        if (courtId != null) {
            reservas.removeIf(r -> !courtId.equals(r.pista.idPista));
        }
        if (userId != null) {
            reservas.removeIf(r -> !userId.equals(r.usuario.id));
        }

        return reservas;
    }

    @GetMapping("/availability")
    public Map<Long, List<String>> disponibilidadGlobal(@RequestParam LocalDate date) {
        Map<Long, List<String>> resultado = new HashMap<>();

        pistaService.listarPistas().forEach(pista ->
                resultado.put(
                        pista.idPista,
                        disponibilidadService.calcularDisponibilidad(pista.idPista, date)
                )
        );

        return resultado;
    }

    private boolean esAdmin(Usuario usuario) {
        return usuario.rol != null && "ADMIN".equalsIgnoreCase(usuario.rol.nombreRol);
    }
}

package edu.comillas.icai.gitt.pat.spring.jpa3.entity;

import jakarta.persistence.*;

import java.util.Date;

@Entity
public class Pista {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    public Long idPista;

    @Column(nullable = false, unique = true)
    public String nombre;

    @Column(nullable = false)
    public String ubicacion;

    @Column(nullable = false)
    public Double precioHora;

    @Column(nullable = false)
    public Boolean activa;

    @Column(nullable = false)
    public Date fechaAlta;


}

package edu.comillas.icai.gitt.pat.spring.jpa3.entity;

import com.fasterxml.jackson.annotation.JsonAlias;
import jakarta.persistence.*;

import java.util.Date;

@Entity
public class Pista {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    @JsonAlias({"id_pista"})
    public Long idPista;

    @Column(nullable = false, unique = true)
    public String nombre;

    @Column(nullable = false)
    public String ubicacion;

    @Column(nullable = false)
    public Double precioHora;

    @Column(nullable = false)
    public Boolean activa;

    @Column(nullable = false)
    public Date fechaAlta;


}

package edu.comillas.icai.gitt.pat.spring.jpa3.security;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpMethod;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.factory.PasswordEncoderFactories;
import org.springframework.security.crypto.password.NoOpPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;

import java.util.List;

@Configuration
@EnableWebSecurity
@EnableMethodSecurity
public class SecurityConfig {

    @Bean
    public PasswordEncoder passwordEncoder() {
        var delegating = (org.springframework.security.crypto.password.DelegatingPasswordEncoder)
                PasswordEncoderFactories.createDelegatingPasswordEncoder();
        delegating.setDefaultPasswordEncoderForMatches(NoOpPasswordEncoder.getInstance());
        return delegating;
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {

        http.cors(Customizer.withDefaults());

        http.csrf(csrf -> csrf.disable());

        http.headers(headers -> headers.frameOptions(frame -> frame.sameOrigin()));

        http.sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS));

        http.authorizeHttpRequests(auth -> auth
                .requestMatchers(HttpMethod.OPTIONS, "/**").permitAll()
                .requestMatchers("/h2-console/**").permitAll()
                .requestMatchers("/pistaPadel/auth/register", "/pistaPadel/auth/login", "/pistaPadel/health", "/error").permitAll()
                .anyRequest().authenticated()
        );

        http.formLogin(form -> form.disable());
        http.httpBasic(Customizer.withDefaults());

        return http.build();
    }

    @Bean
    public AuthenticationManager authenticationManager(AuthenticationConfiguration authConfig) throws Exception {
        return authConfig.getAuthenticationManager();
    }

    @Bean
    CorsConfigurationSource corsConfigurationSource() {
        CorsConfiguration configuration = new CorsConfiguration();

        configuration.setAllowedOriginPatterns(List.of(
                "https://juan-pan.github.io",
                "https://*.github.io",
                "http://localhost:*",
                "http://127.0.0.1:*"
        ));
        configuration.setAllowedMethods(List.of("GET", "POST", "PATCH", "DELETE", "OPTIONS"));
        configuration.setAllowedHeaders(List.of("*"));
        configuration.setAllowCredentials(true);

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/**", configuration);

        return source;
    }
}

package edu.comillas.icai.gitt.pat.spring.jpa3.security;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpMethod;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.factory.PasswordEncoderFactories;
import org.springframework.security.crypto.password.NoOpPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;

import java.util.List;

@Configuration
@EnableWebSecurity
@EnableMethodSecurity
public class SecurityConfig {

    @Bean
    public PasswordEncoder passwordEncoder() {
        var delegating = (org.springframework.security.crypto.password.DelegatingPasswordEncoder)
                PasswordEncoderFactories.createDelegatingPasswordEncoder();
        delegating.setDefaultPasswordEncoderForMatches(NoOpPasswordEncoder.getInstance());
        return delegating;
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {

        http.cors(Customizer.withDefaults());

        http.csrf(csrf -> csrf.disable());

        http.headers(headers -> headers.frameOptions(frame -> frame.sameOrigin()));

        http.sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS));

        http.authorizeHttpRequests(auth -> auth
                .requestMatchers(HttpMethod.OPTIONS, "/**").permitAll()
                .requestMatchers("/h2-console/**").permitAll()
                .requestMatchers("/pistaPadel/auth/register", "/pistaPadel/auth/login", "/pistaPadel/health", "/error").permitAll()
                .requestMatchers(HttpMethod.GET, "/pistaPadel/courts", "/pistaPadel/courts/**", "/pistaPadel/reservations/availability").permitAll()
                .anyRequest().authenticated()
        );

        http.formLogin(form -> form.disable());
        http.httpBasic(Customizer.withDefaults());

        return http.build();
    }

    @Bean
    public AuthenticationManager authenticationManager(AuthenticationConfiguration authConfig) throws Exception {
        return authConfig.getAuthenticationManager();
    }

    @Bean
    CorsConfigurationSource corsConfigurationSource() {
        CorsConfiguration configuration = new CorsConfiguration();

        configuration.setAllowedOriginPatterns(List.of(
                "https://juan-pan.github.io",
                "https://*.github.io",
                "http://localhost:*",
                "http://127.0.0.1:*"
        ));
        configuration.setAllowedMethods(List.of("GET", "POST", "PATCH", "DELETE", "OPTIONS"));
        configuration.setAllowedHeaders(List.of("*"));
        configuration.setAllowCredentials(true);

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/**", configuration);

        return source;
    }
}

package edu.comillas.icai.gitt.pat.spring.jpa3.E2E;

import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.jdbc.AutoConfigureTestDatabase;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.boot.test.web.client.TestRestTemplate;
import org.springframework.http.*;
import org.springframework.test.annotation.DirtiesContext;

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.DEFINED_PORT)
@DirtiesContext(classMode = DirtiesContext.ClassMode.BEFORE_EACH_TEST_METHOD)
@AutoConfigureTestDatabase(replace = AutoConfigureTestDatabase.Replace.ANY)
class PistaPadelE2EFullTest {

    @Autowired
    TestRestTemplate client;

    private HttpHeaders jsonHeaders() {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_JSON);
        return headers;
    }

    private String registerUser(String email) {
        String body = """
                {
                  "nombre": "User",
                  "apellidos": "Test",
                  "telefono": "123456789",
                  "email": "%s",
                  "password": "aaaaaaA1"
                }
                """.formatted(email);

        client.exchange(
                "/pistaPadel/auth/register",
                HttpMethod.POST,
                new HttpEntity<>(body, jsonHeaders()),
                String.class
        );

        return email;
    }

    private HttpHeaders authHeaders(String email) {
        HttpHeaders headers = jsonHeaders();
        if (email.equals("admin@padel.com")) {
            headers.setBasicAuth(email, "1234");
        } else {
            headers.setBasicAuth(email, "aaaaaaA1");
        }
        return headers;
    }

    @Test
    void createCourtTest() {

        String adminEmail = "admin@padel.com"; // User created in data.sql as ADMIN

        HttpHeaders headers = authHeaders(adminEmail);

        String body = """
                {
                  "nombre": "Pista Test 1",
                  "ubicacion": "Interior",
                  "precioHora": 20,
                  "activa": true
                }
                """;

        ResponseEntity<String> response = client.exchange(
                "/pistaPadel/courts",
                HttpMethod.POST,
                new HttpEntity<>(body, headers),
                String.class
        );

        Assertions.assertEquals(HttpStatus.CREATED, response.getStatusCode());
    }

    @Test
    void createReservationTest() {

        String adminEmail = "admin@padel.com";
        HttpHeaders adminHeaders = authHeaders(adminEmail);

        String email = "usertest1@email.com";
        registerUser(email);
        HttpHeaders userHeaders = authHeaders(email);

        String courtBody = """
                {
                  "nombre": "Pista Test 2",
                  "ubicacion": "Exterior",
                  "precioHora": 25,
                  "activa": true
                }
                """;

        client.exchange("/pistaPadel/courts", HttpMethod.POST,
                new HttpEntity<>(courtBody, adminHeaders), String.class);

        String reservationBody = """
                {
                  "pista": { "id_pista": 1 },
                  "fechaReserva": "2026-03-10",
                  "horaInicio": "18:00:00",
                  "duracionMinutos": 60
                }
                """;

        ResponseEntity<String> response = client.exchange(
                "/pistaPadel/reservations",
                HttpMethod.POST,
                new HttpEntity<>(reservationBody, userHeaders),
                String.class
        );

        Assertions.assertEquals(HttpStatus.CREATED, response.getStatusCode());
    }

    @Test
    void reservationConflictTest() {

        String adminEmail = "admin@padel.com";
        HttpHeaders adminHeaders = authHeaders(adminEmail);

        String email = "usertest2@email.com";
        registerUser(email);
        HttpHeaders userHeaders = authHeaders(email);

        String courtBody = """
                {
                  "nombre": "Pista Test 3",
                  "ubicacion": "Interior",
                  "precioHora": 20,
                  "activa": true
                }
                """;

        client.exchange("/pistaPadel/courts", HttpMethod.POST,
                new HttpEntity<>(courtBody, adminHeaders), String.class);

        String reservation = """
                {
                  "pista": { "id_pista": 2 },
                  "fechaReserva": "2026-03-10",
                  "horaInicio": "18:00:00",
                  "duracionMinutos": 60
                }
                """;

        client.exchange("/pistaPadel/reservations",
                HttpMethod.POST, new HttpEntity<>(reservation, userHeaders), String.class);

        ResponseEntity<String> conflict = client.exchange(
                "/pistaPadel/reservations",
                HttpMethod.POST,
                new HttpEntity<>(reservation, userHeaders),
                String.class
        );

        Assertions.assertEquals(HttpStatus.CONFLICT, conflict.getStatusCode());
    }

    @Test
    void getReservationsTest() {

        String email = "usertest3@email.com";
        registerUser(email);
        HttpHeaders headers = authHeaders(email);

        ResponseEntity<String> response = client.exchange(
                "/pistaPadel/reservations",
                HttpMethod.GET,
                new HttpEntity<>(headers),
                String.class
        );

        Assertions.assertEquals(HttpStatus.OK, response.getStatusCode());
    }

    @Test
    void availabilityTest() {

        ResponseEntity<String> response = client.exchange(
                "/pistaPadel/reservations/availability?fecha=2026-03-10&idPista=1",
                HttpMethod.GET,
                null,
                String.class
        );

        // May be 404 if path doesn't exist, we will verify the exact path or expect ok
        Assertions.assertTrue(response.getStatusCode().is2xxSuccessful() || response.getStatusCode() == HttpStatus.NOT_FOUND);
    }
}

package edu.comillas.icai.gitt.pat.spring.jpa3.E2E;

import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.jdbc.AutoConfigureTestDatabase;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.boot.test.web.client.TestRestTemplate;
import org.springframework.http.*;
import org.springframework.test.annotation.DirtiesContext;

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.DEFINED_PORT)
@DirtiesContext(classMode = DirtiesContext.ClassMode.BEFORE_EACH_TEST_METHOD)
@AutoConfigureTestDatabase(replace = AutoConfigureTestDatabase.Replace.ANY)
class PistaPadelE2EFullTest {

    @Autowired
    TestRestTemplate client;

    private HttpHeaders jsonHeaders() {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_JSON);
        return headers;
    }

    private String registerUser(String email) {
        String body = """
                {
                  "nombre": "User",
                  "apellidos": "Test",
                  "telefono": "123456789",
                  "email": "%s",
                  "password": "aaaaaaA1"
                }
                """.formatted(email);

        client.exchange(
                "/pistaPadel/auth/register",
                HttpMethod.POST,
                new HttpEntity<>(body, jsonHeaders()),
                String.class
        );

        return email;
    }

    private HttpHeaders authHeaders(String email) {
        HttpHeaders headers = jsonHeaders();
        if (email.equals("admin@padel.com")) {
            headers.setBasicAuth(email, "1234");
        } else {
            headers.setBasicAuth(email, "aaaaaaA1");
        }
        return headers;
    }

    @Test
    void createCourtTest() {

        String adminEmail = "admin@padel.com"; // User created in data.sql as ADMIN

        HttpHeaders headers = authHeaders(adminEmail);

        String body = """
                {
                  "nombre": "Pista Test 1",
                  "ubicacion": "Interior",
                  "precioHora": 20,
                  "activa": true
                }
                """;

        ResponseEntity<String> response = client.exchange(
                "/pistaPadel/courts",
                HttpMethod.POST,
                new HttpEntity<>(body, headers),
                String.class
        );

        Assertions.assertEquals(HttpStatus.CREATED, response.getStatusCode());
    }

    @Test
    void createReservationTest() {

        String adminEmail = "admin@padel.com";
        HttpHeaders adminHeaders = authHeaders(adminEmail);

        String email = "usertest1@email.com";
        registerUser(email);
        HttpHeaders userHeaders = authHeaders(email);

        String courtBody = """
                {
                  "nombre": "Pista Test 2",
                  "ubicacion": "Exterior",
                  "precioHora": 25,
                  "activa": true
                }
                """;

        client.exchange("/pistaPadel/courts", HttpMethod.POST,
                new HttpEntity<>(courtBody, adminHeaders), String.class);

        String reservationBody = """
                {
                  "pista": { "idPista": 1 },
                  "fechaReserva": "2026-03-10",
                  "horaInicio": "18:00:00",
                  "duracionMinutos": 60
                }
                """;

        ResponseEntity<String> response = client.exchange(
                "/pistaPadel/reservations",
                HttpMethod.POST,
                new HttpEntity<>(reservationBody, userHeaders),
                String.class
        );

        Assertions.assertEquals(HttpStatus.CREATED, response.getStatusCode());
    }

    @Test
    void reservationConflictTest() {

        String adminEmail = "admin@padel.com";
        HttpHeaders adminHeaders = authHeaders(adminEmail);

        String email = "usertest2@email.com";
        registerUser(email);
        HttpHeaders userHeaders = authHeaders(email);

        String courtBody = """
                {
                  "nombre": "Pista Test 3",
                  "ubicacion": "Interior",
                  "precioHora": 20,
                  "activa": true
                }
                """;

        client.exchange("/pistaPadel/courts", HttpMethod.POST,
                new HttpEntity<>(courtBody, adminHeaders), String.class);

        String reservation = """
                {
                  "pista": { "idPista": 1 },
                  "fechaReserva": "2026-03-10",
                  "horaInicio": "18:00:00",
                  "duracionMinutos": 60
                }
                """;

        client.exchange("/pistaPadel/reservations",
                HttpMethod.POST, new HttpEntity<>(reservation, userHeaders), String.class);

        ResponseEntity<String> conflict = client.exchange(
                "/pistaPadel/reservations",
                HttpMethod.POST,
                new HttpEntity<>(reservation, userHeaders),
                String.class
        );

        Assertions.assertEquals(HttpStatus.CONFLICT, conflict.getStatusCode());
    }

    @Test
    void getReservationsTest() {

        String email = "usertest3@email.com";
        registerUser(email);
        HttpHeaders headers = authHeaders(email);

        ResponseEntity<String> response = client.exchange(
                "/pistaPadel/reservations",
                HttpMethod.GET,
                new HttpEntity<>(headers),
                String.class
        );

        Assertions.assertEquals(HttpStatus.OK, response.getStatusCode());
    }

    @Test
    void availabilityTest() {

        ResponseEntity<String> response = client.exchange(
                "/pistaPadel/courts/1/availability?date=2026-03-10",
                HttpMethod.GET,
                null,
                String.class
        );

        Assertions.assertTrue(response.getStatusCode().is2xxSuccessful());
    }
}
